import React from 'react'
import { css } from '@linaria/core'
import { colors } from '../theme'

const svgCss = css`
  display: block;
  flex-shrink: 0;
`

const svgProgressCircleCss = css`
  fill: none;
  transition: stroke-dashoffset 200ms;
`

const svgRemainingCircleCss = css`
  fill: none;
  opacity: 0.5;
`

const svgCircleTextCss = css`
  fill: ${colors.gray100};
  font-size: 0.6rem;
  text-anchor: middle;
`

const iconSize = 24
const textPositionAdjustment = 4
const center = 12
const radius = 9.5
const strokeWidth = 1.5
const circumference = 2 * Math.PI * radius
const transform = `rotate(-90, ${center}, ${center})`
const progressColor = colors.yellow40
const remainingProgressColor = colors.gray40

function ProgressIcon({ progress = 0, ...props }) {
  const progressOffset = ((100 - progress) / 100) * circumference

  return (
    <svg className={svgCss} width={iconSize} height={iconSize} {...props}>
      <circle
        className={svgRemainingCircleCss}
        stroke={remainingProgressColor}
        cx={center}
        cy={center}
        r={radius}
        strokeWidth={strokeWidth}
      />
      <circle
        className={svgProgressCircleCss}
        stroke={progressColor}
        cx={center}
        cy={center}
        r={radius}
        strokeWidth={strokeWidth}
        strokeDasharray={circumference}
        strokeDashoffset={progressOffset}
        transform={transform}
      />
      <text className={svgCircleTextCss} x={center} y={center + textPositionAdjustment}>
        {progress}
      </text>
    </svg>
  )
}

export default ProgressIcon
