import React, { useCallback, useRef, useEffect, memo } from 'react'
import { css } from '@linaria/core'
import { useTranslation } from 'react-i18next'
import { useSpring, animated } from '@react-spring/web'
import { useDrag } from 'react-use-gesture'
import { ContentCheck, NoticeLoading, NoticeImportant, ContentRemove } from '@fs/zion-icon'
import { colors } from '../theme'
import { Paragraph } from '../typography'
import Ellipsis from '../ellipsis'
import { IconButton } from '../buttons/icon-button'
import { usePageWidth } from '../responsive'
import ProgressIcon from './ProgressIcon'
import ProgressOverlayStatus from './ProgressOverlayStatus'
import MarginBox from '../margin-box'
import Row from '../row'
import { textDirection } from '../rtl-support'

const progressItemCss = css`
  background-color: ${colors.gray00};
  border-bottom: 1px solid ${colors.gray05};
  overflow: hidden;
  margin: 0;
  list-style: none;
`

const progressItemInnerCss = css`
  min-height: 52px;
  &[status='failed'] {
    --special-type-color: ${colors.danger70};
  }

  &[status='successful'] {
    --special-type-color: ${colors.green70};
  }
`

const { IN_PROGRESS, SUCCESSFUL, FAILED } = ProgressOverlayStatus

function StatusIcon({ status, percent, id }) {
  const { t } = useTranslation()

  const ariaPercent = status === SUCCESSFUL ? 100 : percent
  const isIndeterminate = percent === undefined || percent === null || percent === '' || Number.isNaN(Number(percent))
  const sharedProps = {
    role: 'progressbar',
    'aria-valuenow': isIndeterminate ? undefined : ariaPercent, // undefined is enough in Chrome and Safari to set the "indeterminate" state on the element
    'aria-valuemin': status !== SUCCESSFUL && isIndeterminate ? -1 : 0, // Firefox needs a negative min/max to set the "indeterminate" state
    'aria-valuemax': status !== SUCCESSFUL && isIndeterminate ? -1 : 100, // Firefox needs a negative min/max to set the "indeterminate" state
  }

  switch (status) {
    case IN_PROGRESS: {
      const percentRounded = Math.round(Number.parseFloat(percent))
      return Number.isInteger(percentRounded) ? (
        <ProgressIcon progress={percentRounded} {...sharedProps} id={id} />
      ) : (
        <NoticeLoading size="sm" color={colors.yellow70} {...sharedProps} id={id} />
      )
    }
    case FAILED: {
      return (
        <NoticeImportant
          size="sm"
          color={colors.danger70}
          {...sharedProps}
          id={id}
          aria-label={t('common-ui:error.label')} // using label instead of valuetext because Firefox does not support valuetext (as of Jun 2025)
        />
      )
    }
    case SUCCESSFUL: {
      return <ContentCheck size="sm" color={colors.green70} {...sharedProps} id={id} aria-valuenow={100} />
    }
    default: {
      return null
    }
  }
}

const defaults = {
  show: { x: 0, y: 0 },
  hide: (direction) => (direction === 'RIGHT' ? { x: 450, y: 0 } : { x: -450, y: 0 }),
  large: {
    targetDistance: 56,
  },
  small: {
    targetDistance: 36,
  },
}

function ProgressItem({ progressItem, removeItem, dismissOverlay, groupId, singleMode }) {
  const [t] = useTranslation()
  const isRtl = textDirection() === 'rtl'
  const defaultDismissDirection = isRtl ? 'RIGHT' : 'LEFT'
  const dragDirectionRef = useRef(defaultDismissDirection)
  const mode = usePageWidth()({ default: 'small', md: 'large' })
  const control = useRef(defaults[mode])
  const shouldRemove = useRef(false)

  /** Handles the slide in/out animation of a progress item. */
  const [{ x, y }, api] = useSpring(() => ({
    from: defaults.hide(defaultDismissDirection),
    to: defaults.show,
    onRest: () => {
      if (shouldRemove.current) {
        /** Only remove the item after the slide out animation has occurred, otherwise the slide out animation doesn't work. */
        removeItem(groupId, progressItem.id)
        shouldRemove.current = false
      }
    },
  }))

  /** Hides the item by sliding to the left or right depending on which direction
   *  the user dragged the item. */
  const hide = useCallback(() => {
    api.start(defaults.hide(dragDirectionRef.current))
  }, [api])

  /** Change the animation control when mode changes. */
  useEffect(() => {
    control.current = defaults[mode]
  }, [mode])

  /** Perform the slide out animation and set the flag to remove the item when the animation finishes. */
  const removeItemAnimated = useCallback(() => {
    shouldRemove.current = true
    hide()
  }, [hide])

  /** Attempt to cancel this item. */
  const cancel = useCallback(async () => {
    const canCancel = await progressItem.onCancel()

    /** Cancel the item if onCancel returns true or nothing. */
    if (canCancel || canCancel === undefined) {
      /** If there's only one progress item in the list, just dismiss the entire overlay instead of only the item.  This makes for a better
       *  animation because it only runs overlay slide out animation, instead of running the item slide out animation and then the overlay
       *  slide out animation. */
      if (singleMode) {
        dismissOverlay(dragDirectionRef.current)
      } else {
        removeItemAnimated()
      }
    }
  }, [dismissOverlay, progressItem, removeItemAnimated, singleMode])

  /** Cancel the item if the drag would cause the item move off the screen. */
  const cancelAfterDrag = useCallback(
    (distanceDragged, directionVector, velocity, targetDistance) => {
      const trajectory = distanceDragged + velocity * 15 * directionVector

      /** If the drag will result in the item being dragged beyond the target distance, cancel it. */
      if (Math.abs(trajectory) > Math.abs(targetDistance)) {
        dragDirectionRef.current = directionVector > 0 ? 'RIGHT' : 'LEFT'
        cancel()
      }
    },
    [cancel]
  )

  /** Handle dragging the item to the left or right. */
  const bind = useDrag(({ movement: [mx], velocity, direction, down }) => {
    const newPosition = { ...defaults.show }
    const distanceDragged = mx

    if (progressItem.status === IN_PROGRESS) {
      if (down) {
        newPosition.x = distanceDragged / 3
      } else {
        cancelAfterDrag(distanceDragged, direction[0], velocity, control.current.targetDistance)
      }

      api.start(newPosition)
    }
  })

  return (
    <animated.li className={progressItemCss} style={{ x, y }} {...bind()}>
      <MarginBox marginX="xs" marginY="pico">
        <Row alignY="middle" gutters="xxs" className={progressItemInnerCss} status={progressItem.status}>
          <StatusIcon noShrinkX status={progressItem.status} percent={progressItem.percent} />
          <Paragraph growX size="sm" secondary={progressItem.status === IN_PROGRESS}>
            <Ellipsis lineClamp={2}>{progressItem.message}</Ellipsis>
          </Paragraph>
          {progressItem.status === IN_PROGRESS && (
            <IconButton
              noShrinkX
              title={t('progress-overlay.cancel', 'Click to cancel')}
              Icon={ContentRemove}
              color="gray"
              onClick={cancel}
            />
          )}
        </Row>
      </MarginBox>
    </animated.li>
  )
}

export default memo(ProgressItem)
