import React from 'react'
import { css } from '@linaria/core'
import ProgressItem from './ProgressItem'

const progressItemsCss = css`
  max-height: 280px;
  overflow-y: auto;
  overflow-x: hidden;
  /* better mobile scrolling */
  overflow-scrolling: touch;
  -webkit-overflow-scrolling: touch;
`

function ProgressItems({ progressItemGroups, removeItem, dismissOverlay, singleMode }) {
  return (
    <ul className={progressItemsCss}>
      {Object.keys(progressItemGroups).map((groupId) =>
        progressItemGroups[groupId].progressItems.map((progressItem) => (
          <ProgressItem
            key={progressItem.id}
            progressItem={progressItem}
            removeItem={removeItem}
            dismissOverlay={dismissOverlay}
            groupId={groupId}
            singleMode={singleMode}
          />
        ))
      )}
    </ul>
  )
}

export default ProgressItems
