import React, { useState, useRef, useCallback, useEffect, useMemo } from 'react'
import { css } from '@linaria/core'
import { boolAttr, useAnimationFrames, useEvent, useRandomId } from '@fs/zion-frontend-friends'
import { useSpring, animated } from '@react-spring/web'
import ProgressItems from './ProgressItems'
import { Theme, colors } from '../theme'
import Elevate from '../elevation'
import Portal from '../portal'
import { ExpanderContent, Expander } from '../expander'
import useCancelClickAway from '../use-click-away/useCancelClickAway'
import useFocusManager from '../use-focus-manager'
import useAutoFocus from '../use-auto-focus/useAutoFocus'
import { usePageWidth } from '../responsive'
import { textDirection } from '../rtl-support'
import ProgressOverlayHeader from './ProgressOverlayHeader'
import { getFocusableChildren, getFirstTabbableItem, getLastTabbableItem } from '../use-focus-manager/useFocusManager'

const progressOverlayCss = css`
  z-index: 2; /* Create a stacking context, so all things inside this overlay will be contained (and on top of the main ui) */
  position: fixed;
  max-height: calc(320px + var(--spacer-nano));
  touch-action: none;
  user-select: none;
  /* Align to bottom of visual viewport to remain visible when iOS on-screen keyboard is open */
  top: calc(
    var(--visual-viewport-height, 100dvh) - var(--overlay-height, 0) - var(--role-indicator-border, 0) - var(
        --spacer-nano
      )
  );
  inset-inline-start: calc(var(--role-indicator-border, 0) + var(--spacer-nano));
  width: calc(100% - var(--role-indicator-border, 0) * 2 - var(--spacer-nano) * 2);

  &[is-large-screen] {
    width: 400px;
  }

  & h2 {
    outline: none; // h2 is what receives focus when the overlay opens, but we want the focus-visible outline to be on the overlay itself
  }
`

const elevationCss = css`
  background: ${colors.gray02};
  border-radius: 8px;
  overflow: hidden;

  &:has(h2:focus-visible) {
    outline: 3px solid ${colors.gray70};
    outline-offset: -5px;
  }
`

const getDefaults = (isRtl = false) => ({
  show: { x: 0, y: 0 },
  large: {
    targetDistance: 56,
    hide: () => ({ x: (isRtl ? -1 : 1) * -450, y: 0 }),
  },
  small: {
    targetDistance: 36,
    hide: (direction) => {
      let hidePosition = { x: 0, y: 450 } // Slide down
      // Slide in a physical direction based on swipe, RTL-independent
      if (direction === 'LEFT') {
        hidePosition = { x: -450, y: 0 } // Slide left
      } else if (direction === 'RIGHT') {
        hidePosition = { x: 450, y: 0 } // Slide right
      }
      return hidePosition
    },
  },
})

function ProgressOverlay({
  progressItemGroups,
  flattenedProgressItems,
  removeItem,
  removeAllItems,
  setScreenBottom,
  headerMessage,
  focusBackRef,
}) {
  const [expanded, setExpanded] = useState(true)
  const expanderAriaControlsId = useRandomId()
  const headerId = useRandomId()
  const mode = usePageWidth()({ default: 'small', md: 'large' })
  const defaults = useMemo(() => getDefaults(textDirection() === 'rtl'), [])
  const control = useRef(defaults[mode])
  const shouldRemoveOverlay = useRef(false)
  const overlayRef = useRef()
  const headerRef = useRef()
  const progressItemCount = flattenedProgressItems.length

  const checkHeight = useCallback(() => {
    const { height } = overlayRef.current?.getBoundingClientRect() || { height: 0 }
    overlayRef.current?.style.setProperty('--overlay-height', `${height}px`)
    setScreenBottom(mode === 'small' ? height : 0)
  }, [mode, setScreenBottom])

  useAnimationFrames(checkHeight)

  useAutoFocus({
    isOpen: flattenedProgressItems?.length, // using a number for isOpen as we want to refocus the header if the list changes
    enabled: true, // always enabled because if the overlay is rendered at all, there are progress items in our current architecture
    focusRef: headerRef,
    containerRef: overlayRef,
  })

  useFocusManager({
    enabled: flattenedProgressItems?.length > 0 && focusBackRef?.current,
    containerRef: overlayRef,
    handler: (_, tabCycle) => {
      // if the user tabs/shift-tabs out of the overlay, we want to focus the element
      // that was focused before the overlay opened
      if (focusBackRef?.current && !overlayRef.current?.contains(focusBackRef.current)) {
        focusBackRef.current?.focus()
        focusBackRef.current = null // reset the ref so we don't focus it again
        return
      }

      // otherwise, we want to just cycle through the focusable elements in the DOM
      // note that we have to add this logic because useFocusManager has already
      // prevented the default behavior of the tab key at this point
      if (overlayRef.current?.contains(document.activeElement)) {
        const focusableElements = getFocusableChildren(document.body).filter((el) => !overlayRef.current?.contains(el))
        const nextElement =
          tabCycle === 'forward' ? getFirstTabbableItem(focusableElements) : getLastTabbableItem(focusableElements)
        if (!nextElement) return
        nextElement?.focus()
      }
    },
  })

  /** Handles the overlay slide in/out animation.  Note that the to/from are initially the same. This prevents
   * the animation from happening immediately.  It needs to wait until the expander animation is done.
   * See 'expanderTransitionEnd()'. */
  const [{ x, y }, api] = useSpring(() => {
    return {
      from: defaults[mode].hide(),
      to: defaults[mode].hide(),
      onRest: () => {
        if (shouldRemoveOverlay.current) {
          /** Remove the progress items after the animation, otherwise the animation doesn't render because the
           * overlay disappears beforehand. */
          removeAllItems()
          setScreenBottom(0)
          shouldRemoveOverlay.current = false
        }
      },
    }
  })

  /** Change the animation control when mode changes. */
  useEffect(() => {
    control.current = defaults[mode]
    api.start(defaults.show)
  }, [mode, api, defaults])

  /** Animate the slide out of the entire overlay and set the flag to remove all items. */
  const dismissOverlay = useCallback(
    (direction) => {
      Object.keys(progressItemGroups).forEach((groupId) => progressItemGroups[groupId].onDismiss?.())
      shouldRemoveOverlay.current = true
      const position = defaults[mode].hide(direction)
      api.start(position)
      focusBackRef.current?.focus()
      focusBackRef.current = null
    },
    [progressItemGroups, defaults, mode, api, focusBackRef]
  )

  const handleRemove = useEvent((...args) => {
    removeItem(...args)
    headerRef.current?.focus() // ensure focus is returned to the header after removing an item
  })

  return (
    <Portal>
      <Theme theme="night" transparent>
        <animated.div
          className={progressOverlayCss}
          is-large-screen={boolAttr(mode === 'large')}
          style={{ x, y }}
          ref={overlayRef}
        >
          <Elevate z={6} className={elevationCss} role="dialog" aria-modal="false" aria-labelledby={headerId}>
            {/* eslint-disable-next-line jsx-a11y/no-static-element-interactions -- the onMouseDown on the outer div is to prevent multiple overlays closing. */}
            <div onMouseDown={useCancelClickAway()}>
              <ProgressOverlayHeader
                headerMessage={headerMessage}
                flattenedProgressItems={flattenedProgressItems}
                expanded={expanded}
                setExpanded={setExpanded}
                expanderAriaControlsId={expanderAriaControlsId}
                dismissOverlay={dismissOverlay}
                defaultShowPosition={defaults.show}
                targetDistance={control.current.targetDistance}
                springApi={api}
                id={headerId}
                ref={headerRef}
              />
              <Expander open={expanded} setOpen={setExpanded} ariaControlsId={expanderAriaControlsId}>
                <ExpanderContent data-testid="progress-overlay-expander">
                  <ProgressItems
                    progressItemGroups={progressItemGroups}
                    removeItem={handleRemove}
                    dismissOverlay={dismissOverlay}
                    singleMode={progressItemCount < 2}
                  />
                </ExpanderContent>
              </Expander>
            </div>
          </Elevate>
        </animated.div>
      </Theme>
    </Portal>
  )
}

export default ProgressOverlay
