import React, { forwardRef, useCallback } from 'react'
import { useDrag } from 'react-use-gesture'
import { useTranslation } from 'react-i18next'
import { MenuClose, ArrowCaret } from '@fs/zion-icon'
import { H2 } from '../typography'
import FeedbackText from '../feedback-text'
import { IconButton } from '../buttons/icon-button'
import Ellipsis from '../ellipsis'
import ProgressOverlayStatus from './ProgressOverlayStatus'
import MarginBox from '../margin-box'
import Row from '../row'

const { IN_PROGRESS, SUCCESSFUL, FAILED } = ProgressOverlayStatus

const headerMessageIcu = `
{totalItemCount, plural,
  =1 {
    {status, select,
      stillProcessing {Processing 1 item}
      allCompleted {1 item successful}
      allFailed {Can't process item}
      other {Processing 1 item}
    }
  }
  other {
    {status, select,
      stillProcessing {Processing {inProgressItemCount} of {totalItemCount} items}
      allCompleted {{successfulItemCount} of {totalItemCount} items successful}
      allFailed {Can't process items}
      other {Processing {inProgressItemCount} of {totalItemCount} items}
    }
  }
}
`

function getCountsGroupedByStatus(flattenedProgressItems) {
  return flattenedProgressItems.reduce(
    (counts, progressItem) => {
      counts[progressItem.status]++
      return counts
    },
    { [IN_PROGRESS]: 0, [SUCCESSFUL]: 0, [FAILED]: 0 }
  )
}

function getDefaultHeaderMessage(statusCounts, totalItemCount, t) {
  const inProgressItemCount = statusCounts[IN_PROGRESS]
  const successfulItemCount = statusCounts[SUCCESSFUL]
  const failedItemCount = statusCounts[FAILED]
  const values = { status: 'allCompleted', totalItemCount, inProgressItemCount, successfulItemCount }

  if (inProgressItemCount > 0) {
    values.status = 'stillProcessing'
  } else if (failedItemCount === totalItemCount) {
    values.status = 'allFailed'
  }

  return t('progress-overlay.header', headerMessageIcu, values)
}

function ProgressOverlayHeader(
  {
    headerMessage,
    flattenedProgressItems,
    expanded,
    setExpanded,
    expanderAriaControlsId,
    dismissOverlay,
    defaultShowPosition,
    targetDistance,
    springApi,
    id,
  },
  ref
) {
  const statusCounts = getCountsGroupedByStatus(flattenedProgressItems)
  const hasItemsInProgress = statusCounts[IN_PROGRESS] > 0
  const [t] = useTranslation()
  const dismissTitle = t('progress-overlay.dismiss-all', 'Click to dismiss all')

  let expanderTitle
  if (expanded) {
    expanderTitle = t('progress-overlay.collapse', 'Click to collapse')
  } else {
    expanderTitle = t('progress-overlay.expand', 'Click to expand')
  }

  /** Collapse or expand the overlay if the header is dragged far enough. */
  const showOrHideAfterDrag = useCallback(
    (distanceDragged, direction, velocity, isDraggingUp) => {
      const directionVector = Math.abs(direction[1])
      const trajectory = Math.abs(distanceDragged) + velocity * 15 * directionVector

      /** If the header is dragged enough up or down, collapse or expand the overlay. */
      const shouldToggle = (isDraggingUp && !expanded) || (!isDraggingUp && expanded)
      if (trajectory > targetDistance && shouldToggle) {
        setExpanded(!expanded)
      }
    },
    [setExpanded, expanded, targetDistance]
  )

  /** Handle dragging the overlay header up or down to collapse or expand the overlay. */
  const expandCollapseAnimator = useDrag(({ movement: [, my], velocity, direction, down }) => {
    const newPosition = { ...defaultShowPosition }
    const distanceDragged = my
    const isDraggingUp = distanceDragged < 0

    if (down) {
      newPosition.y = distanceDragged / (isDraggingUp ? 8 : 3)
      showOrHideAfterDrag(distanceDragged, direction, velocity, isDraggingUp)
    }

    springApi.start(newPosition)
  })

  return (
    <MarginBox marginX="xs" marginY="pico" {...expandCollapseAnimator()}>
      <Row alignY="middle" gutters="sm">
        <FeedbackText type="normal" growX>
          <H2
            size="H6"
            tabIndex={-1} // We focus the header for better accessibility, like we do in our other overlays
            id={id}
            ref={ref}
          >
            <Ellipsis lineClamp={2} style={{ fontWeight: 'normal' }}>
              {headerMessage || getDefaultHeaderMessage(statusCounts, flattenedProgressItems.length, t)}
            </Ellipsis>
          </H2>
        </FeedbackText>
        <IconButton
          noShrinkX
          onClick={() => setExpanded((prev) => !prev)}
          title={expanderTitle}
          Icon={ArrowCaret}
          color="gray"
          iconDirection={expanded ? 'down' : 'up'}
          aria-expanded={expanded ? 'true' : 'false'}
          aria-controls={expanderAriaControlsId}
        />
        {!hasItemsInProgress && (
          <IconButton noShrinkX title={dismissTitle} Icon={MenuClose} color="gray" onClick={dismissOverlay} />
        )}
      </Row>
    </MarginBox>
  )
}

export default forwardRef(ProgressOverlayHeader)
